     8→import { getPostsBasePath, getPostUrl } from '@/lib/urls';
     9→import { buildPostJsonLd, serializeJsonLd, resolveImageUrl } from '@/lib/json-ld';
    10→import RedirectPage from '@/components/RedirectPage';
    11→
    12→function safeDecodeParam(param: string): string {
    13→  try {
    14→    return decodeURIComponent(param);
    15→  } catch {
    16→    return param;
    17→  }
    18→}
    19→
    20→function resolvePostFromParam(rawSlug: string) {
    21→  const decoded = safeDecodeParam(rawSlug);
    22→  return (
    23→    getPostBySlug(decoded) ||
    24→    getPostBySlug(rawSlug) ||
    25→    getPostBySlug(decoded.normalize('NFC')) ||
    26→    getPostBySlug(decoded.normalize('NFD'))
    27→  );
    28→}
    29→
    30→/**
    31→ * Generates the static paths for all blog posts at build time.
    32→ * This ensures fast page loads and SEO optimization.
    33→ */
    34→export async function generateStaticParams() {
    35→  if (getPostsBasePath() !== 'posts') return [{ slug: '_' }]; // Route disabled; custom path handles this
    36→  const posts = getAllPosts();
    37→
    38→  // Include a post if its canonical URL is /posts/[slug] (normal render),
    39→  // or if /posts/[slug] appears in its redirectFrom list (redirect page).
    40→  const basePath = getPostsBasePath();
    41→  const filtered = posts.filter(p => {
    42→    const canonical = getPostUrl(p);
    43→    if (canonical === `/${basePath}/${p.slug}`) return true;
    44→    // autoPaths or customPaths moved this post — include only if it opts into a redirect here
    45→    return (p.redirectFrom ?? []).includes(`/${basePath}/${p.slug}`);
    46→  });
    47→
    48→  if (filtered.length === 0) return [{ slug: '_' }];
    49→  // Work around Next dev static-param checks for percent-encoded Unicode paths
    50→  // under `output: "export"` by including encoded variants only in development.
    51→  // Production export keeps raw segment values.
    52→  const slugs = new Set<string>();
    53→  for (const post of filtered) {
    54→    slugs.add(post.slug);
    55→    if (process.env.NODE_ENV !== 'production') {
    56→      slugs.add(encodeURIComponent(post.slug));
    57→    }
    58→  }
    59→  return Array.from(slugs).map((slug) => ({ slug }));
    60→}
    61→
    62→export const dynamicParams = false;
    63→
    64→export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    65→  const { slug: rawSlug } = await params;
    66→  const post = resolvePostFromParam(rawSlug);
    67→
    68→  if (!post) {
    69→    return {
    70→      title: 'Post Not Found',
    71→    };
    72→  }
    73→
    74→  const siteUrl = siteConfig.baseUrl.replace(/\/+$/, '');
    75→  const canonicalUrl = getPostUrl(post);
    76→  const currentPath = `/${getPostsBasePath()}/${safeDecodeParam(rawSlug)}`;
    77→
    78→  // For redirect pages, return minimal metadata pointing to the canonical URL
    79→  if (canonicalUrl !== currentPath) {
    80→    return {
    81→      title: post.title,
    82→      alternates: { canonical: `${siteUrl}${canonicalUrl}` },
    83→    };
    84→  }
    85→
    86→  const ogImage = resolveImageUrl(post.coverImage, siteConfig.ogImage, siteUrl);
    87→
    88→  return {
    89→    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    90→    description: post.excerpt,
    91→    openGraph: {
    92→      title: post.title,
    93→      description: post.excerpt,
    94→      type: 'article',
    95→      publishedTime: post.date,
    96→      authors: post.authors,
    97→      images: [
    98→        {
    99→          url: ogImage,
   100→          width: 1200,
   101→          height: 630,
   102→          alt: post.title,
   103→        },
   104→      ],
   105→      siteName: resolveLocale(siteConfig.title),
   106→    },
   107→    twitter: {
   108→      card: 'summary_large_image',
   109→      title: post.title,
   110→      description: post.excerpt,
   111→      images: [ogImage],
   112→    },
   113→  };
   114→}
   115→
   116→export default async function PostPage({
   117→  params,
   118→}: {
   119→  params: Promise<{ slug: string }>;
   120→}) {
   121→  const { slug: rawSlug } = await params;
   122→  const slug = safeDecodeParam(rawSlug);
   123→  const post = resolvePostFromParam(rawSlug);
   124→
   125→  if (!post) {
   126→    notFound();
   127→  }
